SELECT COUNT(vp.passenger_id) AS total_passengers
  FROM voyage_passengers vp
  WHERE vp.voyage_id = 0;

SELECT COUNT(*)
FROM passengers
WHERE has_children = 1 AND pclass = 2;

SELECT passenger_id, age
FROM passengers
WHERE age > (SELECT AVG(age) FROM passengers);

SELECT COUNT(passenger_id) AS number_of_passengers
FROM voyage_passengers
WHERE boarding_location = 'Southampton' AND voyage_id = 1;

SELECT vp.boarding_location, vp.passenger_id
FROM voyage_passengers vp
WHERE vp.voyage_id = 1;

SELECT COUNT(*) AS total_passengers_who_boarded_at_Cherbourg
FROM voyage_passengers
WHERE boarding_location = 'Cherbourg';
